package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	User    string
	Message string
}

var comments = []Comment{
	{"Alice", "This is a comment!"},
	{"Bob", "<b>I love Go!</b>"},
	{"Charlie", "<i>Good job on the website.</i>"},
}

var tmpl = template.Must(template.New("comments").Parse(`
<html>
	<body>
		<h1>User Comments</h1>
		{{range .}}
			<div>
				<h2>{{.User}}</h2>
				<p>{{.Message}}</p>
			</div>
		{{end}}
	</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl.Execute(w, comments)
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}